import{p as o,bh as i,I as t,U as e}from"./chunks/framework.BpabEsSf.js";const _=JSON.parse('{"title":"自动填充与保底机制","description":"","frontmatter":{"title":"自动填充与保底机制","date":"2026-05-16T14:15:00.000Z","permalink":"/reference/autofill","categories":["使用指南"],"tags":["Android","自动填充"]},"headers":[],"relativePath":"02.配置/02.相关文档/03.Monica-Android-自动填充与保底机制.md","filePath":"02.配置/02.相关文档/03.Monica-Android-自动填充与保底机制.md","lastUpdated":1778928321000}'),r={name:"02.配置/02.相关文档/03.Monica-Android-自动填充与保底机制.md"};function n(l,a,d,s,c,h){return i(),t("div",null,[...a[0]||(a[0]=[e('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /02.配置\\02.相关文档\\03.Monica-Android-自动填充与保底机制.md for this page in Markdown format</div><h1 id="⌨️-monica-android-自动填充方式" tabindex="-1">⌨️ Monica Android 自动填充方式 <a class="header-anchor" href="#⌨️-monica-android-自动填充方式" aria-label="Permalink to &quot;⌨️ Monica Android 自动填充方式&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">概述</p><p>为了防止因系统或应用兼容性问题导致自动填充无法使用，Monica for Android 提供了三种不同的自动填充方式以及一种最终保底机制，确保用户在各种应用场景下都能顺利完成填充。</p></div><hr><h2 id="🛠️-三种自动填充方式" tabindex="-1">🛠️ 三种自动填充方式 <a class="header-anchor" href="#🛠️-三种自动填充方式" aria-label="Permalink to &quot;🛠️ 三种自动填充方式&quot;">​</a></h2><h3 id="_1-自动填充-autofill" tabindex="-1">1. 自动填充 autofill <a class="header-anchor" href="#_1-自动填充-autofill" aria-label="Permalink to &quot;1. 自动填充 autofill&quot;">​</a></h3><ul><li><strong>原理</strong>：利用 Android 系统提供的标准 autofill 链路进行自动填充。</li><li><strong>开启方法</strong>：在系统设置中选择 <code>Monica autofill</code> 为自动填充服务。</li></ul><h3 id="_2-monica-键盘" tabindex="-1">2. Monica 键盘 <a class="header-anchor" href="#_2-monica-键盘" aria-label="Permalink to &quot;2. Monica 键盘&quot;">​</a></h3><ul><li><strong>原理</strong>：类似于“密码键盘”应用。需要聚焦表单，然后点击键盘上的填充按钮，通过 <kbd>Tab</kbd> 键切换遍历表单，按照字段进行自动填充。</li><li><strong>开启方法</strong>：在系统设置的输入法设置中，勾选启用 <code>Monica 键盘</code>。</li></ul><h3 id="_3-控制栏磁贴-无障碍" tabindex="-1">3. 控制栏磁贴（无障碍） <a class="header-anchor" href="#_3-控制栏磁贴-无障碍" aria-label="Permalink to &quot;3. 控制栏磁贴（无障碍）&quot;">​</a></h3><ul><li><strong>原理</strong>：利用系统的无障碍权限进行自动填充，作为以上两种方案的保底机制。</li><li><strong>开启方法</strong>：在下拉控制栏中添加 Monica 磁贴，并在系统设置的无障碍服务中给予 <code>Monica Pass</code> 无障碍权限。</li></ul><hr><h2 id="🛡️-最终保底机制" tabindex="-1">🛡️ 最终保底机制 <a class="header-anchor" href="#🛡️-最终保底机制" aria-label="Permalink to &quot;🛡️ 最终保底机制&quot;">​</a></h2><p>如果以上三种填充方式皆不可用，可以通过结合<strong>控制栏磁贴</strong>与<strong>通知权限</strong>来实现快速复制填充。</p><h3 id="开启方法" tabindex="-1">开启方法 <a class="header-anchor" href="#开启方法" aria-label="Permalink to &quot;开启方法&quot;">​</a></h3><ul><li>在下拉控制栏添加磁贴。</li><li>在系统设置中给予 <code>Monica Pass</code> <strong>通知权限</strong>。</li></ul><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>下拉控制栏，点击 <strong>Monica 磁贴</strong> 进入密码自动填充页面。</li><li>点击想要填充的密码列表项，选择 <strong>“复制账号稍后复制密码”</strong>。</li><li>此时系统会马上复制账号到剪贴板，同时发送密码到系统通知栏。</li><li>粘贴完账号后，<strong>点击通知栏的该条通知</strong>，即可自动复制密码，完成后续粘贴。</li></ol>',18)])])}const g=o(r,[["render",n]]);export{_ as __pageData,g as default};
